const registry = [
  {
    "metricKey": "ads_spend",
    "displayName": "Get Ad Spend",
    "dateMode": "range-ready"
  },
  {
    "metricKey": "ctr",
    "displayName": "Get CTR",
    "dateMode": "range-ready"
  },
  {
    "metricKey": "sales_ppc",
    "displayName": "Get Sales PPC",
    "dateMode": "range-ready"
  },
  {
    "metricKey": "clicks",
    "displayName": "Get Clicks",
    "dateMode": "range-ready"
  },
  {
    "metricKey": "units_ppc",
    "displayName": "Get Units PPC",
    "dateMode": "range-ready"
  }
];
const raw = String($json.INCLUDE_LIST || '').trim().toLowerCase();
const selectedMetrics = raw ? [...new Set(raw.split(',').map((value) => value.trim()).filter(Boolean).filter((metricKey) => registry.some((entry) => entry.metricKey === metricKey)))] : [];
return [{
  json: {
    ...$json,
    INCLUDE_LIST: selectedMetrics.join(','),
    selectedMetrics,
    runAll: selectedMetrics.length === 0,
    groupKey: 'ads',
    groupMetrics: registry.map((entry) => entry.metricKey),
    summary: [],
    registry,
    remainingRegistry: registry,
  },
}];

const input = $input.first().json;
const summary = (input.summary || []).map((item) => ({
  groupKey: 'ads',
  metricKey: item.metricKey,
  displayName: item.displayName,
  selected: item.selected,
  status: item.status,
  errorMessage: item.errorMessage ?? null,
  startedAt: item.startedAt ?? null,
  finishedAt: item.finishedAt ?? null,
}));
const totals = summary.reduce((acc, item) => {
  acc.total += 1;
  acc[item.status] = (acc[item.status] || 0) + 1;
  return acc;
}, { total: 0, success: 0, failed: 0, skipped: 0 });
const firstFailure = summary.find((item) => item.status === 'failed');
const selectedMetrics = input.runAll ? (input.groupMetrics || []) : (input.selectedMetrics || []);
const groupStatus = totals.failed > 0 ? 'failed' : totals.success > 0 ? 'success' : 'skipped';
const startedAt = summary.find((item) => item.startedAt)?.startedAt || null;
const finishedAt = new Date().toISOString();
return [{
  json: {
    groupKey: 'ads',
    groups: [{
      groupKey: 'ads',
      status: groupStatus,
      selectedMetrics,
      errorMessage: firstFailure ? firstFailure.errorMessage : null,
      startedAt,
      finishedAt,
    }],
    summary,
    totals,
  },
}];

const seed = $('Set Credentials').first().json;
const input = $input.first().json;
const issuedAt = new Date().toISOString();

const refreshBufferSeconds = Number(seed.AUTH_REFRESH_BUFFER_SECONDS || input.AUTH_REFRESH_BUFFER_SECONDS || 300);

