      },
      meta: {
        refreshBufferSeconds,
      },
    },
  },
}];

function b64urlFromString(str) {
  return Buffer.from(str, 'utf8')
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function b64urlFromBytes(bytes) {
  return Buffer.from(bytes)
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function hexToBytes(hex) {
  const out = new Uint8Array(hex.length / 2);
  for (let i = 0; i < out.length; i++) {
    out[i] = parseInt(hex.slice(i * 2, i * 2 + 2), 16);
  }
  return out;
}

function bytesToBigInt(bytes) {
  let n = 0n;
  for (let i = 0; i < bytes.length; i++) {
    n = (n << 8n) | BigInt(bytes[i]);
  }
  return n;
}

function bigIntToBytes(num, length) {
  const out = new Uint8Array(length);
  let x = num;
  for (let i = length - 1; i >= 0; i--) {
    out[i] = Number(x & 0xffn);
    x >>= 8n;
  }
  return out;
}

function modPow(base, exp, mod) {
  let result = 1n;
  let b = base % mod;
  let e = exp;
  while (e > 0n) {
    if (e & 1n) result = (result * b) % mod;
    b = (b * b) % mod;
    e >>= 1n;
  }
  return result;
}

function readAsn1Element(bytes, offset) {
  const tag = bytes[offset++];
  const lenByte = bytes[offset++];
  let length = 0;
  if ((lenByte & 0x80) === 0) {
    length = lenByte;
  } else {
    const numBytes = lenByte & 0x7f;
    for (let i = 0; i < numBytes; i++) {
      length = (length << 8) | bytes[offset++];
    }
  }
  const valueStart = offset;
  const valueEnd = valueStart + length;
  return { tag, valueStart, valueEnd, nextOffset: valueEnd };
}

function readAsn1Integer(bytes, offset) {
  const el = readAsn1Element(bytes, offset);
  if (el.tag !== 0x02) throw new Error('Invalid ASN.1 INTEGER');
  let start = el.valueStart;
  while (start < el.valueEnd - 1 && bytes[start] === 0x00) start++;
  return { value: bytesToBigInt(bytes.slice(start, el.valueEnd)), nextOffset: el.nextOffset };
}

function parsePkcs8RsaPrivateKey(pem) {
  const der = Buffer.from(
    pem
      .replace(/-----BEGIN PRIVATE KEY-----/g, '')
      .replace(/-----END PRIVATE KEY-----/g, '')
      .replace(/\s+/g, ''),
    'base64'
  );
  const bytes = new Uint8Array(der);

  const top = readAsn1Element(bytes, 0);
  if (top.tag !== 0x30) throw new Error('Invalid PKCS#8');

  let o = top.valueStart;
  const version = readAsn1Element(bytes, o);
  if (version.tag !== 0x02) throw new Error('Invalid PKCS#8 version');
  o = version.nextOffset;

  const alg = readAsn1Element(bytes, o);
  if (alg.tag !== 0x30) throw new Error('Invalid PKCS#8 algorithm identifier');
  o = alg.nextOffset;

  const pk = readAsn1Element(bytes, o);
  if (pk.tag !== 0x04) throw new Error('Invalid PKCS#8 privateKey');

  const rsaBytes = bytes.slice(pk.valueStart, pk.valueEnd);
  const rsaSeq = readAsn1Element(rsaBytes, 0);
  if (rsaSeq.tag !== 0x30) throw new Error('Invalid RSAPrivateKey');

  let r = rsaSeq.valueStart;
  r = readAsn1Element(rsaBytes, r).nextOffset; // version
  const nEl = readAsn1Integer(rsaBytes, r); r = nEl.nextOffset;
  const eEl = readAsn1Integer(rsaBytes, r); r = eEl.nextOffset;
  const dEl = readAsn1Integer(rsaBytes, r);

  return {
    n: nEl.value,
    e: eEl.value,
    d: dEl.value,
  };
}

function rotr(x, n) {
  return ((x >>> n) | (x << (32 - n))) >>> 0;
}

function sha256(msgBytes) {
  const K = [
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
    0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
    0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
    0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
    0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
    0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
  ];

  const H = [
    0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a,
    0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
  ];

  const bitLen = msgBytes.length * 8;
  const withOne = msgBytes.length + 1;
  const padLen = (64 - ((withOne + 8) % 64)) % 64;
  const totalLen = withOne + padLen + 8;
  const data = new Uint8Array(totalLen);
  data.set(msgBytes, 0);
  data[msgBytes.length] = 0x80;
  const hi = Math.floor(bitLen / 0x100000000);
  const lo = bitLen >>> 0;
  data[totalLen - 8] = (hi >>> 24) & 0xff;
  data[totalLen - 7] = (hi >>> 16) & 0xff;
  data[totalLen - 6] = (hi >>> 8) & 0xff;
  data[totalLen - 5] = hi & 0xff;
  data[totalLen - 4] = (lo >>> 24) & 0xff;
  data[totalLen - 3] = (lo >>> 16) & 0xff;
  data[totalLen - 2] = (lo >>> 8) & 0xff;
  data[totalLen - 1] = lo & 0xff;

  const W = new Uint32Array(64);

  for (let i = 0; i < data.length; i += 64) {
    for (let t = 0; t < 16; t++) {
      const j = i + t * 4;
      W[t] = ((data[j] << 24) | (data[j + 1] << 16) | (data[j + 2] << 8) | data[j + 3]) >>> 0;
    }
    for (let t = 16; t < 64; t++) {
      const s0 = (rotr(W[t - 15], 7) ^ rotr(W[t - 15], 18) ^ (W[t - 15] >>> 3)) >>> 0;
      const s1 = (rotr(W[t - 2], 17) ^ rotr(W[t - 2], 19) ^ (W[t - 2] >>> 10)) >>> 0;
      W[t] = (((W[t - 16] + s0) >>> 0) + ((W[t - 7] + s1) >>> 0)) >>> 0;
    }

    let a = H[0], b = H[1], c = H[2], d = H[3];
    let e = H[4], f = H[5], g = H[6], h = H[7];

    for (let t = 0; t < 64; t++) {
      const S1 = (rotr(e, 6) ^ rotr(e, 11) ^ rotr(e, 25)) >>> 0;
      const ch = ((e & f) ^ (~e & g)) >>> 0;
      const temp1 = (((((h + S1) >>> 0) + ch) >>> 0) + ((K[t] + W[t]) >>> 0)) >>> 0;
      const S0 = (rotr(a, 2) ^ rotr(a, 13) ^ rotr(a, 22)) >>> 0;
      const maj = ((a & b) ^ (a & c) ^ (b & c)) >>> 0;
      const temp2 = (S0 + maj) >>> 0;

      h = g;
      g = f;
      f = e;
      e = (d + temp1) >>> 0;
      d = c;
      c = b;
      b = a;
      a = (temp1 + temp2) >>> 0;
    }

    H[0] = (H[0] + a) >>> 0;
    H[1] = (H[1] + b) >>> 0;
    H[2] = (H[2] + c) >>> 0;
    H[3] = (H[3] + d) >>> 0;
    H[4] = (H[4] + e) >>> 0;
    H[5] = (H[5] + f) >>> 0;
    H[6] = (H[6] + g) >>> 0;
    H[7] = (H[7] + h) >>> 0;
  }

  const out = new Uint8Array(32);
  for (let i = 0; i < 8; i++) {
    out[i * 4] = (H[i] >>> 24) & 0xff;
    out[i * 4 + 1] = (H[i] >>> 16) & 0xff;
    out[i * 4 + 2] = (H[i] >>> 8) & 0xff;
    out[i * 4 + 3] = H[i] & 0xff;
  }
  return out;
}

function rsassaPkcs1V15Sha256Sign(messageUtf8, privateKeyPem) {
  const key = parsePkcs8RsaPrivateKey(privateKeyPem);
  const k = Math.ceil(key.n.toString(2).length / 8);

  const hash = sha256(new TextEncoder().encode(messageUtf8));
  const digestInfoPrefix = hexToBytes('3031300d060960864801650304020105000420');
  const tLen = digestInfoPrefix.length + hash.length;
  const psLen = k - tLen - 3;
  if (psLen < 8) throw new Error('RSA key too short for PKCS#1 v1.5 SHA-256');

  const em = new Uint8Array(k);
  em[0] = 0x00;
  em[1] = 0x01;
  for (let i = 0; i < psLen; i++) em[2 + i] = 0xff;
  em[2 + psLen] = 0x00;
  em.set(digestInfoPrefix, 3 + psLen);
  em.set(hash, 3 + psLen + digestInfoPrefix.length);

  const m = bytesToBigInt(em);
  const s = modPow(m, key.d, key.n);
  return bigIntToBytes(s, k);
}

const input = $input.first().json;
const serviceAccountEmail = $('Set Credentials').first().json["✅GOOGLE_SERVICE_ACCOUNT_EMAIL"];
const privateKeyPem = String($('Set Credentials').first().json["✅GOOGLE_PRIVATE_KEY"] || '').replace(/\\n/g, '\n');
const scope = $('Set Credentials').first().json["✅GOOGLE_SCOPE"] || 'https://www.googleapis.com/auth/spreadsheets.readonly';

if (!serviceAccountEmail || !privateKeyPem) {
  throw new Error('Missing GOOGLE_SERVICE_ACCOUNT_EMAIL or GOOGLE_PRIVATE_KEY');
}

const now = Math.floor(Date.now() / 1000);
const header = { alg: 'RS256', typ: 'JWT' };
const payload = {
  iss: serviceAccountEmail,
  scope,
  aud: 'https://oauth2.googleapis.com/token',
  iat: now,
  exp: now + 3600,
};

const encodedHeader = b64urlFromString(JSON.stringify(header));
const encodedPayload = b64urlFromString(JSON.stringify(payload));
const signingInput = `${encodedHeader}.${encodedPayload}`;

const signatureBytes = rsassaPkcs1V15Sha256Sign(signingInput, privateKeyPem);
const signature = b64urlFromBytes(signatureBytes);
const assertion = `${signingInput}.${signature}`;

return [
  {
    json: {
      ...input,
      assertion,
    },
  },
];

const errorMsg = String($input.first().json.error?.message || '');
const match = errorMsg.match(/duplicate of\s*:\s*([a-f0-9-]+)/i);

if (!match) {
  throw new Error(errorMsg || 'Amazon Ads create-report request failed without duplicate report id');
}

return [{ json: { reportId: match[1] } }];

function parseRetryAfterSeconds(value) {
  if (value === null || value === undefined || value === '') return 0;
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
}

function nextBackoffSeconds(previousAttempt, retryAfterSeconds) {
  const capped = Math.min(300, 60 * (2 ** Math.max(1, previousAttempt + 1)));
  const jitter = Math.floor(Math.random() * 31);
  return Math.max(capped + jitter, retryAfterSeconds || 0, 60);
}

const input = $input.first().json || {};
const previousAttempt = Number(input.pollAttempt || 0);
const error = input.error || null;
const rawStatus = String(input.status || '').toUpperCase();

if (error) {
  const message = String(error.message || input.message || 'Unknown polling error');
  const httpCode = Number(error.httpCode || input.httpCode || 0);
  const retryAfterSeconds = parseRetryAfterSeconds(error.retryAfter || error.headers?.['retry-after'] || error.response?.headers?.['retry-after']);

  if (httpCode === 429 || message.toLowerCase().includes('too many requests')) {
    return [{
      json: {
        ...input,
        status: 'THROTTLED',
        pollAttempt: previousAttempt + 1,
        nextWaitSeconds: nextBackoffSeconds(previousAttempt, retryAfterSeconds),
      },
    }];
  }

  throw new Error(message);
}

if (rawStatus === 'FAILED' || rawStatus === 'CANCELLED') {
  throw new Error(`Amazon Ads report ${rawStatus}: ${input.failureReason || 'No failure reason provided'}`);
}

if (rawStatus === 'COMPLETED') {
  return [{
    json: {
      ...input,
      status: 'COMPLETED',
      pollAttempt: previousAttempt,
    },
  }];
}

return [{
  json: {
    ...input,
    status: rawStatus || 'PENDING',
    pollAttempt: previousAttempt + 1,
    nextWaitSeconds: nextBackoffSeconds(previousAttempt, 0),
  },
}];

function toNumber(v) {
  if (v === null || v === undefined) return 0;
  const s = String(v).replace(/[$,%\s,]/g, '');
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function normalize(value) {
  return String(value || '').trim().replace(/[ _]+/g, ' ').toUpperCase();
}

function colToA1(colIndex1Based) {
  let n = colIndex1Based;
  let out = '';
  while (n > 0) {
    const m = (n - 1) % 26;
    out = String.fromCharCode(65 + m) + out;
    n = Math.floor((n - 1) / 26);
  }
  return out;
}

const sheet = $json;
const values = sheet.values || [];
const reportData = $('Extract from File').first().json.data || [];
const sheetName = $('Set Credentials').first().json['✅SHEET_NAME'] || 'MOBILITY';
const row2 = values[1] || [];

const skuCol = row2.findIndex((cell) => normalize(cell) === 'SKU');
const adsCol = row2.findIndex((cell) => normalize(cell) === 'ADS SPEND');

if (skuCol === -1 || adsCol === -1) {
  throw new Error('Could not find SKU and Ads spend columns from row 2');
}

const adsBySku = new Map();
for (const r of reportData) {
  const sku = String(r.advertisedSku || '').trim();
  if (!sku) continue;
  const cost = toNumber(r.cost);
  adsBySku.set(sku, (adsBySku.get(sku) || 0) + cost);
}

const data = [];
for (let i = 2; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  if (!sku || /^SKU$/i.test(sku) || /^IMG$/i.test(sku) || /_TOTALS$/i.test(sku)) continue;
  if (!adsBySku.has(sku)) continue;

  const newAds = Number(adsBySku.get(sku).toFixed(2));
  const rowNumber = i + 1;
  const adsColA1 = colToA1(adsCol + 1);

  data.push({
    range: `${sheetName}!${adsColA1}${rowNumber}`,
    values: [[newAds]]
  });
}

return [{
  json: {
    valueInputOption: 'USER_ENTERED',
    data,
  }
}];

const errorMsg = String($input.first().json.error?.message || '');
const match = errorMsg.match(/duplicate of\s*:\s*([a-f0-9-]+)/i);

if (!match) {
  throw new Error(errorMsg || 'Amazon Ads create-report request failed without duplicate report id');
}

return [{ json: { reportId: match[1] } }];

