  let n = colIndex1Based;
  let out = '';
  while (n > 0) {
    const m = (n - 1) % 26;
    out = String.fromCharCode(65 + m) + out;
    n = Math.floor((n - 1) / 26);
  }
  return out;
}

const sheet = $json; // from Webhook Read Google Sheet
const values = sheet.values || [];
const reportData = $('Extract from File1').first().json.data || [];
const sheetName = $('Set Credentials').first().json['✅SHEET_NAME'] || 'MOBILITY';

// Aggregate clicks and impressions by SKU, then derive CTR.
const metricsBySku = new Map();
for (const row of reportData) {
  const sku = String(row.advertisedSku || '').trim();
  if (!sku) continue;

  const clicks = toNumber(row.clicks);
  const impressions = toNumber(row.impressions);

  if (!metricsBySku.has(sku)) {
    metricsBySku.set(sku, {
      clicks: 0,
      impressions: 0,
    });
  }

  const bucket = metricsBySku.get(sku);
  bucket.clicks = Number((bucket.clicks + clicks).toFixed(4));
  bucket.impressions = Number((bucket.impressions + impressions).toFixed(4));
}

const ctrBySku = new Map();
for (const [sku, metrics] of metricsBySku.entries()) {
  const ctr = metrics.impressions > 0
    ? Number(((metrics.clicks / metrics.impressions) * 100).toFixed(4))
    : 0;
  ctrBySku.set(sku, ctr);
}

// Detect the header row by finding the SKU column in the top section.
let headerRowIdx = -1;
let skuCol = -1;
for (let i = 0; i < Math.min(values.length, 12); i++) {
  const row = values[i] || [];
  const skuIdx = row.findIndex((cell) => String(cell).trim().toUpperCase() === 'SKU');
  if (skuIdx !== -1) {
    headerRowIdx = i;
    skuCol = skuIdx;
  }
}

if (headerRowIdx === -1 || skuCol === -1) {
  throw new Error('Could not find header row with SKU column');
}

const data = [];
const ctrColA1 = colToA1(12); // Column L

for (let i = headerRowIdx + 1; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  if (!sku || !ctrBySku.has(sku)) continue;

  const rowNumber = i + 1;
  data.push({
    range: `${sheetName}!${ctrColA1}${rowNumber}`,
    values: [[ctrBySku.get(sku)]],
  });
}

return [{
  json: {
    valueInputOption: 'USER_ENTERED',
    data,
  },
}];

